// Detectar origen (Mailgun o SendGrid) y normalizar al schema fact_email_events
// Referencia: GHL_Database.txt fact_email_events

const REGEX_EMAIL = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

function cleanStr(val, maxLen) { if (!val) return null; const s = String(val).trim().substring(0, maxLen); return s.length > 0 ? s : null; }
function validateEmail(val) { if (!val) return null; const n = String(val).toLowerCase().trim().substring(0, 255); return REGEX_EMAIL.test(n) ? n : null; }
function parseISODate(val) { if (!val) return null; const ts = Date.parse(String(val)); return isNaN(ts) ? null : new Date(ts).toISOString(); }

const raw     = $input.first().json;
const headers = $input.first().headers || {};
const ua      = (headers['user-agent'] || '').toLowerCase();

let events = [];

// --- Mailgun ---
// Mailgun envía un objeto plano por webhook (un evento por request)
// o puede enviar un array en 'event-data' anidado
if (ua.includes('mailgun') || raw['event-data'] !== undefined || raw['event'] !== undefined) {
  const evData = raw['event-data'] || raw;
  const evType = cleanStr(evData.event || raw.event, 30);
  const msgId  = cleanStr(evData.message?.headers?.['message-id'] || evData['message-id'] || raw['Message-Id'], 200);
  const email  = validateEmail(evData.recipient || evData.email || raw.recipient);

  if (evType && (msgId || email)) {
    events.push({
      event_id:      cleanStr(evData.id || evData.token || (msgId + '_' + Date.now()), 200),
      message_id:    msgId,
      contact_id:    null,  // se correlacionara por email si hace falta
      location_id:   cleanStr(evData['user-variables']?.location_id || raw['location_id'] || '', 50) || 'unknown',
      event_type:    evType,
      email,
      subject:       cleanStr(evData.message?.headers?.subject || evData.subject, 500),
      url:           cleanStr(evData.url || evData['clicked-url'], 2048),
      bounce_type:   cleanStr(evData['delivery-status']?.message ? 'hard' : null, 30),
      bounce_reason: cleanStr(evData['delivery-status']?.message || evData.reason, 2048),
      client_type:   cleanStr(evData['client-info']?.['client-name'], 50),
      device_type:   cleanStr(evData['client-info']?.['device-type'], 30),
      country:       cleanStr(evData['geolocation']?.country, 2),
      esp:           'mailgun',
      occurred_at:   parseISODate(evData.timestamp ? new Date(evData.timestamp * 1000).toISOString() : null) || new Date().toISOString()
    });
  }
}
// --- SendGrid ---
// SendGrid envía un array de eventos por POST
else if (Array.isArray(raw) || (raw[0] && raw[0].sg_event_id !== undefined)) {
  const list = Array.isArray(raw) ? raw : [raw];
  for (const ev of list) {
    const evType  = cleanStr(ev.event, 30);
    const msgId   = cleanStr(ev.smtp_id || ev['smtp-id'] || ev.sg_message_id, 200);
    const email   = validateEmail(ev.email);
    if (!evType) continue;
    events.push({
      event_id:      cleanStr(ev.sg_event_id || (msgId + '_' + Date.now()), 200),
      message_id:    msgId,
      contact_id:    null,
      location_id:   cleanStr(ev.location_id || '', 50) || 'unknown',
      event_type:    evType,
      email,
      subject:       null,
      url:           cleanStr(ev.url, 2048),
      bounce_type:   cleanStr(ev.type, 30),
      bounce_reason: cleanStr(ev.reason, 2048),
      client_type:   cleanStr(ev.useragent, 50),
      device_type:   null,
      country:       null,
      esp:           'sendgrid',
      occurred_at:   parseISODate(ev.timestamp ? new Date(ev.timestamp * 1000).toISOString() : null) || new Date().toISOString()
    });
  }
} else {
  // Formato desconocido — loguear y responder 200 para no causar reintentos
  return [{ json: { _skip: true, reason: 'ESP desconocido' } }];
}

if (events.length === 0) return [{ json: { _skip: true, reason: 'Sin eventos validos' } }];

return events.map(e => ({ json: e }));
